local function _LBI_EXECUTE(_BYTE_ARRAY)
    local _DECODE_MAP = {
        "MOVE", "LOADK", "LOADBOOL", "LOADNIL", "GETUPVAL", "GETGLOBAL", "GETTABLE", "SETGLOBAL",
        "SETUPVAL", "SETTABLE", "NEWTABLE", "SELF", "ADD", "SUB", "MUL", "DIV", "MOD", "POW",
        "UNM", "NOT", "LEN", "CONCAT", "JMP", "EQ", "LT", "LE", "TEST", "TESTSET", "CALL",
        "TAILCALL", "RETURN", "FORLOOP", "FORPREP", "TFORLOOP", "SETLIST", "CLOSE", "CLOSURE", "VARARG"
    }

    local function _DESERIALIZE(_STR)
        local _SOURCE = ""
        for i=1, #_STR do
            _SOURCE = _SOURCE .. string.char(_STR[i])
        end
        local _F, _E = loadstring(_SOURCE)
        if not _F then return warn("[VM ERROR]: " .. tostring(_E)) end
        return _F
    end

    local _SUCCESS, _RESULT = pcall(function()
        local _INIT = _DESERIALIZE(_BYTE_ARRAY)
        if _INIT then return _INIT() end
    end)

    if not _SUCCESS then 
        warn("[VM CRASH]: " .. tostring(_RESULT)) 
    end
end

_LBI_EXECUTE(_DATA)
